 1→import { useEditor } from '@/app/EditorProvider';
 2→import { useProject } from '@/app/ProjectProvider';
 3→import { TOOLS } from '@/editor/tools';
 4→import { detectRooms } from '@/geometry/roomDetection';
 5→import { createRoom } from '@/domain/models';
 6→import styles from './Toolbar.module.css';
 7→
 8→export default function Toolbar({ onNew, onSave, onLoad }) {
 9→  const { activeTool, showGrid, snapEnabled, activeFloorId, dispatch: editorDispatch } = useEditor();
10→  const { project, isDirty, dispatch } = useProject();
11→
12→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
13→
14→  const handleDetectRooms = () => {
15→    const floor = project.floors.find(f => f.id === activeFloorId);
16→    if (!floor || floor.walls.length < 3) return;
17→    const detected = detectRooms(floor.walls);
18→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
19→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
20→  };
21→
22→  return (
23→    <div className={styles.toolbar}>
24→      <div className={styles.group}>
25→        <button className={styles.btn} onClick={onNew}>New</button>
26→        <button className={styles.btn} onClick={onSave}>
27→          {isDirty && <span className={styles.dirtyIndicator} />}
28→          Save
29→        </button>
30→        <button className={styles.btn} onClick={onLoad}>Load</button>
31→      </div>
32→
33→      <div className={styles.group}>
34→        <button
35→          className={`${styles.btn} ${activeTool === TOOLS.SELECT ? styles.active : ''}`}
36→          onClick={() => setTool(TOOLS.SELECT)}
37→          title="Select (V)"
38→        >
39→          Select
40→        </button>
41→        <button
42→          className={`${styles.btn} ${activeTool === TOOLS.WALL ? styles.active : ''}`}
43→          onClick={() => setTool(TOOLS.WALL)}
44→          title="Draw Wall (W)"
45→        >
46→          Wall
47→        </button>
48→        <button
49→          className={`${styles.btn} ${activeTool === TOOLS.DOOR ? styles.active : ''}`}
50→          onClick={() => setTool(TOOLS.DOOR)}
51→          title="Place Door (D)"
52→        >
53→          Door
54→        </button>
55→        <button
56→          className={`${styles.btn} ${activeTool === TOOLS.WINDOW ? styles.active : ''}`}
57→          onClick={() => setTool(TOOLS.WINDOW)}
58→          title="Place Window (N)"
59→        >
60→          Window
61→        </button>
62→      </div>
63→
64→      <div className={styles.group}>
65→        <button
66→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
67→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
68→          title="Toggle Grid"
69→        >
70→          Grid
71→        </button>
72→        <button
73→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
74→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
75→          title="Toggle Snap"
76→        >
77→          Snap
78→        </button>
79→        <button
80→          className={styles.btn}
81→          onClick={handleDetectRooms}
82→          title="Detect Rooms"
83→        >
84→          Detect Rooms
85→        </button>
86→      </div>
87→
88→      <div className={styles.spacer} />
89→    </div>
90→  );
91→}
