  1→import { useState } from 'react';
  2→import { useProject } from '@/app/ProjectProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { wallLength } from '@/geometry/wallGeometry';
  5→import InputField from './InputField';
  6→import styles from './PropertiesPanel.module.css';
  7→
  8→function useUnits() {
  9→  const [unit, setUnit] = useState('mm');
 10→  const isMm = unit === 'mm';
 11→  return {
 12→    unit,
 13→    setUnit,
 14→    suffix: isMm ? 'mm' : 'm',
 15→    toDisplay: (mm) => isMm ? Math.round(mm) : +(mm / 1000).toFixed(3),
 16→    fromDisplay: (v) => isMm ? v : v * 1000,
 17→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 18→  };
 19→}
 20→
 21→function WallProperties({ wall, dispatch, floorId, u }) {
 22→  const len = wallLength(wall);
 23→
 24→  const updateWall = (updates) => {
 25→    dispatch({ type: 'WALL_UPDATE', floorId, wall: { id: wall.id, ...updates } });
 26→  };
 27→
 28→  return (
 29→    <div>
 30→      <div className={styles.title}>Wall</div>
 31→      <div className={styles.subtitle}>Start Point</div>
 32→      <InputField
 33→        label="X" type="number" suffix={u.suffix}
 34→        value={u.toDisplay(wall.start.x)}
 35→        onChange={(v) => updateWall({ start: { ...wall.start, x: u.fromDisplay(v) } })}
 36→      />
 37→      <InputField
 38→        label="Y" type="number" suffix={u.suffix}
 39→        value={u.toDisplay(wall.start.y)}
 40→        onChange={(v) => updateWall({ start: { ...wall.start, y: u.fromDisplay(v) } })}
 41→      />
 42→      <div className={styles.subtitle}>End Point</div>
 43→      <InputField
 44→        label="X" type="number" suffix={u.suffix}
 45→        value={u.toDisplay(wall.end.x)}
 46→        onChange={(v) => updateWall({ end: { ...wall.end, x: u.fromDisplay(v) } })}
 47→      />
 48→      <InputField
 49→        label="Y" type="number" suffix={u.suffix}
 50→        value={u.toDisplay(wall.end.y)}
 51→        onChange={(v) => updateWall({ end: { ...wall.end, y: u.fromDisplay(v) } })}
 52→      />
 53→      <div className={styles.subtitle}>Properties</div>
 54→      <InputField
 55→        label="Thickness" type="number" suffix={u.suffix} step={u.step(10)}
 56→        value={u.toDisplay(wall.thickness)}
 57→        onChange={(v) => updateWall({ thickness: Math.max(50, u.fromDisplay(v)) })}
 58→      />
 59→      <InputField
 60→        label="Length" type="number" suffix={u.suffix}
 61→        value={u.toDisplay(len)}
 62→        readOnly
 63→      />
 64→    </div>
 65→  );
 66→}
