126→function WindowProperties({ window: win, wall, dispatch, floorId, u }) {
127→  const updateWindow = (updates) => {
128→    dispatch({ type: 'WINDOW_UPDATE', floorId, window: { id: win.id, ...updates } });
129→  };
130→
131→  const winType = win.type || 'standard';
132→
133→  return (
134→    <div>
135→      <div className={styles.title}>Window</div>
136→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
137→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Type</label>
138→        <select value={winType} onChange={(e) => updateWindow({ type: e.target.value })}
139→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)',
140→                   borderRadius: 'var(--radius-sm)', fontSize: '12px' }}>
141→          <option value="standard">Standard</option>
142→          <option value="casement">Casement</option>
143→          <option value="fixed">Fixed</option>
144→        </select>
145→      </div>
146→      <InputField
147→        label="Width" type="number" suffix={u.suffix} step={u.step(50)}
148→        value={u.toDisplay(win.width)}
149→        onChange={(v) => updateWindow({ width: Math.max(300, u.fromDisplay(v)) })}
150→      />
151→      <InputField
152→        label="Offset" type="number" suffix={u.suffix}
153→        value={u.toDisplay(win.offset)}
154→        onChange={(v) => updateWindow({ offset: Math.max(0, u.fromDisplay(v)) })}
155→      />
156→      {winType === 'casement' && (
157→        <button
158→          className={styles.deleteBtn}
159→          style={{ marginBottom: '8px', background: 'var(--color-accent)' }}
160→          onClick={() => updateWindow({
161→            openDirection: win.openDirection === 'left' ? 'right' : 'left',
162→          })}
163→        >
164→          Toggle Open Side
165→        </button>
166→      )}
167→      {wall && (
168→        <InputField label="Wall" value={wall.id.split('_').pop()} readOnly />
169→      )}
170→    </div>
171→  );
172→}
