174→function RoomProperties({ room, dispatch, floorId }) {
175→  const areaM2 = room.area ? (room.area / 1_000_000).toFixed(2) : '\u2014';
176→  const updateRoom = (updates) => {
177→    dispatch({ type: 'ROOM_UPDATE', floorId, room: { id: room.id, ...updates } });
178→  };
179→  return (
180→    <div>
181→      <div className={styles.title}>Room</div>
182→      <InputField label="Name" value={room.name} onChange={(v) => updateRoom({ name: v })} />
183→      <InputField label="Area" suffix="m\u00B2" value={areaM2} readOnly />
184→      <InputField label="Color" value={room.color} onChange={(v) => updateRoom({ color: v })} />
185→    </div>
186→  );
187→}
