189→function ProjectSummary({ project, floor }) {
190→  return (
191→    <div>
192→      <div className={styles.title}>Project Summary</div>
193→      <div className={styles.summary}>
194→        <p>Name: {project.name}</p>
195→        <p>Floors: {project.floors.length}</p>
196→        {floor && (
197→          <>
198→            <p>Walls: {floor.walls.length}</p>
199→            <p>Doors: {floor.doors.length}</p>
200→            <p>Windows: {floor.windows.length}</p>
201→          </>
202→        )}
203→      </div>
204→    </div>
205→  );
206→}
