208→export default function PropertiesPanel() {
209→  const { project, dispatch } = useProject();
210→  const { selectedId, selectedType, activeFloorId, dispatch: editorDispatch } = useEditor();
211→  const floor = project.floors.find(f => f.id === activeFloorId);
212→  const u = useUnits();
213→
214→  const handleDelete = () => {
215→    if (!selectedId) return;
216→    if (selectedType === 'wall') {
217→      dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
218→    } else if (selectedType === 'door') {
219→      dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
220→    } else if (selectedType === 'window') {
221→      dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
222→    } else if (selectedType === 'room') {
223→      dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
224→    }
225→    editorDispatch({ type: 'DESELECT' });
226→  };
227→
228→  let content = <ProjectSummary project={project} floor={floor} />;
229→
230→  if (selectedId && floor) {
231→    if (selectedType === 'wall') {
232→      const wall = floor.walls.find(w => w.id === selectedId);
233→      if (wall) {
234→        content = <WallProperties wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
235→      }
236→    } else if (selectedType === 'door') {
237→      const door = floor.doors.find(d => d.id === selectedId);
238→      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
239→      if (door) {
240→        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
241→      }
242→    } else if (selectedType === 'window') {
243→      const win = floor.windows.find(w => w.id === selectedId);
244→      const wall = win ? floor.walls.find(w => w.id === win.wallId) : null;
245→      if (win) {
246→        content = <WindowProperties window={win} wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
247→      }
248→    } else if (selectedType === 'room') {
249→      const room = floor.rooms.find(r => r.id === selectedId);
250→      if (room) {
251→        content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
252→      }
253→    }
254→  }
255→
256→  return (
257→    <div className={styles.panel}>
258→      <div className={styles.unitToggle}>
259→        <span>Units:</span>
260→        <button
261→          className={`${styles.unitBtn} ${u.unit === 'mm' ? styles.unitBtnActive : ''}`}
262→          onClick={() => u.setUnit('mm')}
263→        >mm</button>
264→        <button
265→          className={`${styles.unitBtn} ${u.unit === 'm' ? styles.unitBtnActive : ''}`}
266→          onClick={() => u.setUnit('m')}
267→        >m</button>
268→      </div>
269→      {content}
270→      {selectedId && (
271→        <button className={styles.deleteBtn} onClick={handleDelete}>
272→          Delete {selectedType}
273→        </button>
274→      )}
275→    </div>
276→  );
277→}
