 63→                onClick={() => selectObject(d.id, 'door')}
 64→              >
 65→                Door {d.id.split('_').pop()}
 66→              </div>
 67→            ))}
 68→          </div>
 69→
 70→          <div className={styles.section}>
 71→            <div className={styles.sectionTitle}>
 72→              Windows <span className={styles.count}>{floor.windows.length}</span>
 73→            </div>
 74→            {floor.windows.map(w => (
 75→              <div
 76→                key={w.id}
 77→                className={`${styles.item} ${selectedId === w.id ? styles.itemSelected : ''}`}
 78→                onClick={() => selectObject(w.id, 'window')}
 79→              >
 80→                Window {w.id.split('_').pop()}
 81→              </div>
 82→            ))}
 83→          </div>
 84→
 85→          <div className={styles.section}>
 86→            <div className={styles.sectionTitle}>
 87→              Rooms <span className={styles.count}>{floor.rooms.length}</span>
 88→            </div>
 89→            {floor.rooms.map(r => (
 90→              <div
 91→                key={r.id}
 92→                className={`${styles.item} ${selectedId === r.id ? styles.itemSelected : ''}`}
 93→                onClick={() => selectObject(r.id, 'room')}
 94→              >
 95→                {r.name}
 96→              </div>
 97→            ))}
 98→          </div>
 99→        </>
100→      )}
101→    </div>
102→  );
