  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { useEditorTool } from '@/editor/useEditorTool';
  5→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  6→import { TOOLS } from '@/editor/tools';
  7→import GridRenderer from './GridRenderer';
  8→import WallRenderer from './WallRenderer';
  9→import DoorRenderer from './DoorRenderer';
 10→import WindowRenderer from './WindowRenderer';
 11→import RoomRenderer from './RoomRenderer';
 12→import DimensionRenderer from './DimensionRenderer';
 13→import SelectionOverlay from './SelectionOverlay';
 14→import WallPreview from './WallPreview';
 15→import DoorWindowPreview from './DoorWindowPreview';
 16→import styles from './SvgCanvas.module.css';
 17→
 18→function screenToModel(screenX, screenY, viewport, svgRect) {
 19→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 20→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 21→  return { x, y };
 22→}
 23→
 24→export default function SvgCanvas() {
 25→  const svgRef = useRef(null);
 26→  const isPanning = useRef(false);
 27→  const lastPanPos = useRef({ x: 0, y: 0 });
 28→  const spaceHeld = useRef(false);
 29→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 30→
 31→  const { project, dispatch, getFloor } = useProject();
 32→  const editor = useEditor();
 33→  const {
 34→    activeTool, selectedId, selectedType, toolState,
 35→    viewport, showGrid, snapEnabled, activeFloorId,
 36→    dispatch: editorDispatch,
 37→  } = editor;
 38→
 39→  const floor = getFloor(activeFloorId);
 40→
 41→  const tool = useEditorTool({
 42→    activeTool,
 43→    dispatch,
 44→    editorDispatch,
 45→    getFloor,
 46→    activeFloorId,
 47→    viewport,
 48→    snapEnabled,
 49→    selectedId,
 50→    selectedType,
 51→    toolState,
 52→  });
 53→
 54→  const getModelPos = useCallback((e) => {
 55→    const rect = svgRef.current.getBoundingClientRect();
 56→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 57→  }, [viewport]);
 58→
 59→  const handleMouseDown = useCallback((e) => {
 60→    // Middle mouse or space+left for pan
 61→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 62→      isPanning.current = true;
 63→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 64→      e.preventDefault();
 65→      return;
 66→    }
 67→
 68→    const modelPos = getModelPos(e);
 69→    tool.onMouseDown(modelPos, e);
 70→  }, [getModelPos, tool]);
 71→
 72→  const handleMouseMove = useCallback((e) => {
 73→    if (isPanning.current) {
 74→      const dx = e.clientX - lastPanPos.current.x;
 75→      const dy = e.clientY - lastPanPos.current.y;
 76→      editorDispatch({ type: 'PAN', dx, dy });
 77→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 78→      return;
 79→    }
 80→
 81→    const modelPos = getModelPos(e);
 82→    setCursorPos(modelPos);
 83→    tool.onMouseMove(modelPos, e);
 84→  }, [getModelPos, tool, editorDispatch]);
 85→
 86→  const handleMouseUp = useCallback((e) => {
 87→    if (isPanning.current) {
 88→      isPanning.current = false;
 89→      return;
 90→    }
 91→    const modelPos = getModelPos(e);
 92→    tool.onMouseUp(modelPos, e);
 93→  }, [getModelPos, tool]);
 94→
 95→  const handleDoubleClick = useCallback((e) => {
 96→    const modelPos = getModelPos(e);
 97→    tool.onDoubleClick(modelPos, e);
 98→  }, [getModelPos, tool]);
 99→
100→  const handleWheel = useCallback((e) => {
101→    e.preventDefault();
102→    const rect = svgRef.current.getBoundingClientRect();
103→    const mouseX = e.clientX - rect.left;
104→    const mouseY = e.clientY - rect.top;
105→
106→    const direction = e.deltaY < 0 ? 1 : -1;
107→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
108→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
109→
110→    // Zoom centered on cursor
111→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
112→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
113→
114→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
115→  }, [viewport, editorDispatch]);
116→
117→  useEffect(() => {
118→    const handleKeyDown = (e) => {
119→      if (e.key === ' ') {
120→        spaceHeld.current = true;
121→        e.preventDefault();
122→      }
123→
124→      // Tool shortcuts
125→      if (!e.ctrlKey && !e.metaKey) {
126→        switch (e.key.toLowerCase()) {
127→          case 'v':
128→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
129→            return;
130→          case 'w':
131→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
132→            return;
133→          case 'd':
134→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
135→            return;
136→          case 'n':
137→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
138→            return;
139→        }
140→      }
141→
142→      tool.onKeyDown(e);
143→    };
144→
145→    const handleKeyUp = (e) => {
146→      if (e.key === ' ') {
147→        spaceHeld.current = false;
148→      }
149→    };
150→
151→    window.addEventListener('keydown', handleKeyDown);
152→    window.addEventListener('keyup', handleKeyUp);
153→    return () => {
154→      window.removeEventListener('keydown', handleKeyDown);
155→      window.removeEventListener('keyup', handleKeyUp);
156→    };
157→  }, [tool, editorDispatch]);
158→
159→  // Prevent default context menu on SVG
160→  useEffect(() => {
161→    const svg = svgRef.current;
162→    if (!svg) return;
163→    const prevent = (e) => e.preventDefault();
164→    svg.addEventListener('contextmenu', prevent);
165→    svg.addEventListener('wheel', handleWheel, { passive: false });
166→    return () => {
167→      svg.removeEventListener('contextmenu', prevent);
168→      svg.removeEventListener('wheel', handleWheel);
169→    };
170→  }, [handleWheel]);
171→
172→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor();
173→  const zoomPercent = Math.round(viewport.zoom * 1000);
174→
175→  return (
176→    <div className={styles.canvasContainer}>
177→      <svg
178→        ref={svgRef}
179→        className={styles.svg}
180→        style={{ cursor }}
181→        onMouseDown={handleMouseDown}
182→        onMouseMove={handleMouseMove}
183→        onMouseUp={handleMouseUp}
184→        onDoubleClick={handleDoubleClick}
185→      >
186→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
187→          {showGrid && <GridRenderer />}
188→          {showGrid && (
189→            <rect
190→              x={-100000} y={-100000}
191→              width={200000} height={200000}
192→              fill="url(#grid-major)"
193→              style={{ pointerEvents: 'none' }}
194→            />
195→          )}
196→          {floor && (
197→            <>
198→              <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
199→              <WallRenderer walls={floor.walls} />
200→              <DoorRenderer doors={floor.doors} walls={floor.walls} />
201→              <WindowRenderer windows={floor.windows} walls={floor.walls} />
202→              <DimensionRenderer walls={floor.walls} />
203→              <SelectionOverlay
204→                selectedId={selectedId}
205→                selectedType={selectedType}
206→                floor={floor}
207→                zoom={viewport.zoom}
208→              />
209→              <WallPreview toolState={toolState} activeTool={activeTool} />
210→              <DoorWindowPreview
211→                toolState={toolState}
212→                activeTool={activeTool}
213→                walls={floor.walls}
214→              />
215→            </>
216→          )}
217→        </g>
218→      </svg>
219→      <div className={styles.statusBar}>
220→        <span>X: {Math.round(cursorPos.x)} mm</span>
221→        <span>Y: {Math.round(cursorPos.y)} mm</span>
222→        <span>Zoom: {zoomPercent}%</span>
223→        <span>Tool: {activeTool}</span>
224→      </div>
225→    </div>
226→  );
227→}
